+//! Custom tracing layer for JSONL output.
+//!
+//! This layer produces machine-parseable JSONL logs on stderr while
+//! keeping stdout clean for command payloads.
+
+use std::io::{self, Write};
+use std::sync::Mutex;
+
+use chrono::Utc;
+use tracing::span::{Attributes, Id};
+use tracing::{Event, Subscriber};
+use tracing_subscriber::layer::Context;
+use tracing_subscriber::registry::LookupSpan;
+use tracing_subscriber::Layer;
+
+use super::events::Level;
+
+/// Storage for span context data.
+#[derive(Debug, Clone, Default)]
+struct SpanContext {
+    run_id: Option<String>,
+    session_id: Option<String>,
+    host_id: Option<String>,
+    stage: Option<String>,
+    pid: Option<u32>,
+    start_id: Option<String>,
+}
+
+/// A visitor that extracts field values from tracing events.
+struct JsonFieldVisitor {
+    fields: serde_json::Map<String, serde_json::Value>,
+    message: Option<String>,
+}
+
+impl JsonFieldVisitor {
+    fn new() -> Self {
+        JsonFieldVisitor {
+            fields: serde_json::Map::new(),
+            message: None,
+        }
+    }
+}
+
+impl tracing::field::Visit for JsonFieldVisitor {
+    fn record_str(&mut self, field: &tracing::field::Field, value: &str) {
+        if field.name() == "message" {
+            self.message = Some(value.to_string());
+        } else {
+            self.fields
+                .insert(field.name().to_string(), serde_json::Value::String(value.to_string()));
+        }
+    }
+
+    fn record_debug(&mut self, field: &tracing::field::Field, value: &dyn std::fmt::Debug) {
+        let s = format!("{:?}", value);
+        if field.name() == "message" {
+            self.message = Some(s);
+        } else {
+            self.fields
+                .insert(field.name().to_string(), serde_json::Value::String(s));
+        }
+    }
+
+    fn record_i64(&mut self, field: &tracing::field::Field, value: i64) {
+        self.fields
+            .insert(field.name().to_string(), serde_json::Value::Number(value.into()));
+    }
+
+    fn record_u64(&mut self, field: &tracing::field::Field, value: u64) {
+        self.fields.insert(
+            field.name().to_string(),
+            serde_json::Value::Number(serde_json::Number::from(value)),
+        );
+    }
+
+    fn record_f64(&mut self, field: &tracing::field::Field, value: f64) {
+        if let Some(n) = serde_json::Number::from_f64(value) {
+            self.fields.insert(field.name().to_string(), serde_json::Value::Number(n));
+        }
+    }
+
+    fn record_bool(&mut self, field: &tracing::field::Field, value: bool) {
+        self.fields
+            .insert(field.name().to_string(), serde_json::Value::Bool(value));
+    }
+}
+
+/// A visitor for extracting span context.
+struct SpanContextVisitor {
+    context: SpanContext,
+}
